import { PostHog } from './posthog-rn'
import { PostHogAutocaptureElement, JsonType } from '@posthog/core'
import { PostHogAutocaptureOptions } from './types'

interface Element {
  elementType?: {
    displayName?: string
    name?: string
  }
  memoizedProps?: Record<string, unknown>
  return?: Element
}

const isAnimatedValue = (value: any): boolean => {
  // Check if it's a Reanimated shared value or animated style
  // _isReanimatedSharedValue is the official internal marker for SharedValues
  // Also check for _value property which is present in SharedValues
  return value?._isReanimatedSharedValue === true || (typeof value === 'object' && value !== null && '_value' in value)
}

const flattenStyles = (styles: any): any => {
  const flattened: any = {}

  // Skip if the entire style object is an animated value
  if (isAnimatedValue(styles)) {
    return {}
  }

  if (Array.isArray(styles)) {
    for (const style of styles) {
      Object.assign(flattened, flattenStyles(style))
    }
  } else if (styles && typeof styles === 'object') {
    // Filter out individual animated properties within a regular style object
    // This handles cases like { opacity: animatedValue, backgroundColor: 'red' }
    for (const key in styles) {
      if (!isAnimatedValue(styles[key])) {
        flattened[key] = styles[key]
      }
    }
  }

  return flattened
}

const stringifyStyle = (styles: any): string => {
  const flattened = flattenStyles(styles)

  const str = Object.keys(flattened)
    .map((x) => `${x}:${flattened[x]}`)
    .join(';')

  return str
}

const sanitiseLabel = (label: string): string => {
  return label.replace(/[^a-z0-9]+/gi, '-')
}

export const defaultPostHogLabelProp = 'ph-label'

const captureAttributePrefix = 'data-ph-capture-attribute-'

export const autocaptureFromTouchEvent = (e: any, posthog: PostHog, options: PostHogAutocaptureOptions = {}): void => {
  const {
    noCaptureProp = 'ph-no-capture',
    customLabelProp = defaultPostHogLabelProp,
    maxElementsCaptured = 20,
    ignoreLabels = [],
    propsToCapture = ['style', 'testID', 'accessibilityLabel', customLabelProp, 'children'],
  } = options

  if (!e._targetInst) {
    return
  }
  const elements: PostHogAutocaptureElement[] = []
  const autocaptureProperties: Record<string, JsonType> = {}

  let currentInst: Element | undefined = e._targetInst

  while (
    currentInst &&
    // maxComponentTreeSize will always be defined as we have a defaultProps. But ts needs a check so this is here.
    elements.length < maxElementsCaptured
  ) {
    const el: PostHogAutocaptureElement = {
      tag_name: '',
    }
    const elAutocaptureProperties: Record<string, JsonType> = {}

    const props = currentInst.memoizedProps

    if (props?.[noCaptureProp]) {
      // Immediately ignore events if a no capture is in the chain
      return
    }

    if (props) {
      // Capture data-ph-capture-attribute props as event properties.
      // Element props are only captured from propsToCapture.
      Object.keys(props).forEach((key) => {
        const value = props[key]

        if (key.indexOf(captureAttributePrefix) === 0) {
          const propertyKey = key.slice(captureAttributePrefix.length)
          if (propertyKey && ['string', 'number', 'boolean'].includes(typeof value) && value !== '') {
            elAutocaptureProperties[propertyKey] = value as JsonType
          }
        }

        if (!propsToCapture.includes(key)) {
          return
        }

        if (key === 'style') {
          // Safely handle style prop, especially for animated styles
          try {
            el.attr__style = stringifyStyle(value)
          } catch (error) {
            // Skip style capturing if it fails (e.g., animated styles)
          }
        } else if (['string', 'number', 'boolean'].includes(typeof value)) {
          if (key === 'children') {
            el.$el_text = typeof value === 'string' ? value : JSON.stringify(value)
          } else {
            el[`attr__${key}`] = value as JsonType
          }
        }
      })
    }

    // Try and find a sensible label
    const label =
      typeof props?.[customLabelProp] !== 'undefined'
        ? `${props[customLabelProp]}`
        : currentInst.elementType?.displayName || currentInst.elementType?.name

    Object.assign(autocaptureProperties, elAutocaptureProperties)

    if (label && !ignoreLabels.includes(label)) {
      el.tag_name = sanitiseLabel(label)
      elements.push(el)
    }

    currentInst = currentInst.return
  }

  if (elements.length) {
    // The element that was tapped, may be a child (or grandchild of an element with a customLabelProp (default: ph-label))
    // In this case, the current labels applied obscure the customLabelProp (default: ph-label)
    // To correct this, loop over the elements in reverse, and promote the customLabelProp (default: ph-label)
    const elAttrLabelKey = `attr__${customLabelProp}`
    let lastLabel: string | undefined = undefined

    for (let i = elements.length - 1; i >= 0; i--) {
      const element = elements[i]
      if (element[elAttrLabelKey]) {
        // this element had a customLabelProp (default: ph-label) set, promote it to the lastLabel
        lastLabel = element[elAttrLabelKey] as string
      }

      // if lastLabel is set, update this elements tag_name
      if (lastLabel) {
        element['tag_name'] = lastLabel
      }
    }
    posthog.autocapture('touch', elements, {
      ...autocaptureProperties,
      $touch_x: e.nativeEvent.pageX,
      $touch_y: e.nativeEvent.pageY,
    })
  }
}

import React, { useCallback, useEffect, useMemo } from 'react'
import { GestureResponderEvent, StyleProp, View, ViewStyle } from 'react-native'
import { PostHog, PostHogOptions } from './posthog-rn'
import { autocaptureFromTouchEvent } from './autocapture'
import { useNavigationTracker } from './hooks/useNavigationTracker'
import { PostHogContext } from './PostHogContext'
import { PostHogAutocaptureOptions } from './types'
import { defaultPostHogLabelProp } from './autocapture'

/**
 * Props for the PostHogProvider component.
 *
 * @public
 */
export interface PostHogProviderProps {
  /** The child components to render within the PostHog context */
  children: React.ReactNode
  /** PostHog configuration options */
  options?: PostHogOptions
  /** Your PostHog API key */
  apiKey?: string
  /** An existing PostHog client instance */
  client?: PostHog
  /**
   * Autocapture configuration - can be a boolean or detailed options.
   *
   * When not set, the default behavior is:
   * - `captureScreens`: true
   * - `captureTouches`: false
   * - `captureAppLifecycleEvents`: true
   *
   * Set to `true` to enable all autocapture features (including touches).
   * Set to `false` to disable all autocapture features.
   */
  autocapture?: boolean | PostHogAutocaptureOptions
  /**
   * Enable debug mode for additional logging
   *
   * @default false
   */
  debug?: boolean
  /** Custom styles for the provider wrapper View */
  style?: StyleProp<ViewStyle>
}

function PostHogNavigationHook({
  options,
  client,
}: {
  options?: PostHogAutocaptureOptions
  client?: PostHog
}): JSX.Element | null {
  useNavigationTracker(options?.navigation, options?.navigationRef, client)
  return null
}

/**
 * PostHogProvider is a React component that provides PostHog functionality to your React Native app. You can find all configuration options in the [React Native SDK docs](https://posthog.com/docs/libraries/react-native#configuration-options).
 *
 * Autocapturing navigation requires further configuration. See the [React Native SDK navigation docs](https://posthog.com/docs/libraries/react-native#capturing-screen-views)
 * for more information about autocapturing navigation.
 *
 * This is the recommended way to set up PostHog for React Native. This utilizes the Context API to pass the PostHog client around, enable autocapture.
 *
 * {@label Initialization}
 *
 * @example
 * ```jsx
 * // Add to App.(js|ts)
 * import { usePostHog, PostHogProvider } from 'posthog-react-native'
 *
 * export function MyApp() {
 *     return (
 *         <PostHogProvider apiKey="<ph_project_api_key>" options={{
 *             host: '<ph_client_api_host>',
 *         }}>
 *             <MyComponent />
 *         </PostHogProvider>
 *     )
 * }
 *
 * // And access the PostHog client via the usePostHog hook
 * import { usePostHog } from 'posthog-react-native'
 *
 * const MyComponent = () => {
 *     const posthog = usePostHog()
 *
 *     useEffect(() => {
 *         posthog.capture("event_name")
 *     }, [posthog])
 * }
 *
 * ```
 *
 * @example
 * ```jsx
 * // Using with existing client
 * import { PostHog } from 'posthog-react-native'
 *
 * const posthog = new PostHog('<ph_project_api_key>', {
 *     host: '<ph_client_api_host>'
 * })
 *
 * export function MyApp() {
 *     return (
 *         <PostHogProvider client={posthog}>
 *             <MyComponent />
 *         </PostHogProvider>
 *     )
 * }
 * ```
 *
 * @public
 *
 * @param props - The PostHogProvider props
 */
export const PostHogProvider = ({
  children,
  client,
  options,
  apiKey,
  autocapture,
  style,
  debug = false,
}: PostHogProviderProps): JSX.Element | null => {
  const captureAll = autocapture === true
  const captureNone = autocapture === false

  const posthog = useMemo(() => {
    if (client && apiKey) {
      console.warn(
        'You have provided both a client and an apiKey to PostHogProvider. The apiKey will be ignored in favour of the client.'
      )
    }

    if (client) {
      return client
    }

    const parsedOptions = {
      ...options,
      captureAppLifecycleEvents:
        options?.captureAppLifecycleEvents !== undefined ? options.captureAppLifecycleEvents : !captureNone,
    }

    return new PostHog(apiKey ?? '', parsedOptions)
  }, [client, apiKey]) // eslint-disable-line react-hooks/exhaustive-deps

  const autocaptureOptions = useMemo(
    () => (autocapture && typeof autocapture !== 'boolean' ? autocapture : {}),
    [autocapture]
  )

  const captureTouches = !captureNone && posthog && (captureAll || autocaptureOptions?.captureTouches)
  const captureScreens = !captureNone && posthog && (captureAll || (autocaptureOptions?.captureScreens ?? true)) // Default to true if not set
  const phLabelProp = autocaptureOptions?.customLabelProp || defaultPostHogLabelProp

  useEffect(() => {
    posthog.debug(debug)
  }, [debug, posthog])

  const onTouch = useCallback(
    (type: 'start' | 'move' | 'end', e: GestureResponderEvent) => {
      // TODO: Improve this to ensure we only capture presses and not just ends of a drag for example
      if (!captureTouches) {
        return
      }

      if (type === 'end') {
        autocaptureFromTouchEvent(e, posthog, autocaptureOptions)
      }
    },
    [captureTouches, posthog, autocaptureOptions]
  )

  return (
    <View
      {...{ [phLabelProp]: 'PostHogProvider' }} // Dynamically setting customLabelProp (default: ph-label)
      style={style || { flex: 1 }}
      onTouchEndCapture={captureTouches ? (e) => onTouch('end', e) : undefined}
    >
      <PostHogContext.Provider value={{ client: posthog }}>
        {captureScreens && <PostHogNavigationHook options={autocaptureOptions} client={posthog} />}
        {children}
      </PostHogContext.Provider>
    </View>
  )
}

import { useCallback, useEffect } from 'react'
import { OptionalReactNativeNavigation } from '../optional/OptionalReactNativeNavigation'
import type { PostHog } from '../posthog-rn'
import { PostHogAutocaptureNavigationTrackerOptions } from '../types'
import { useOverridablePostHog } from './utils'
import { PostHogNavigationRef } from '../types'

function _useNavigationTrackerDisabled(): void {
  return
}

function _useNavigationTracker(
  options?: PostHogAutocaptureNavigationTrackerOptions,
  navigationRef?: PostHogNavigationRef,
  client?: PostHog
): void {
  const posthog = useOverridablePostHog(client, 'useNavigationTracker')

  if (!OptionalReactNativeNavigation) {
    // NOTE: This is taken care of by the export, but we keep this here for TS
    throw new Error('No OptionalReactNativeNavigation')
  }

  let routes: any = undefined
  let navigation: any = navigationRef

  try {
    // eslint-disable-next-line react-hooks/rules-of-hooks
    routes = OptionalReactNativeNavigation.useNavigationState((state: any) => state?.routes)
  } catch (error) {
    // useNavigationState might not be available in static navigation setups
    // We'll rely on the navigation object to get the current route
    console.error('useNavigationState error', error)
  }

  try {
    if (!navigation) {
      // eslint-disable-next-line react-hooks/rules-of-hooks
      navigation = OptionalReactNativeNavigation.useNavigation()
    }
  } catch (error) {
    // useNavigation hook might not be available in static navigation setups
    // Navigation tracking will be disabled in this case
    console.error('useNavigation error', error)
    return
  }

  // eslint-disable-next-line react-hooks/rules-of-hooks
  const trackRoute = useCallback((): void => {
    if (!navigation || !posthog) {
      return
    }

    // if you create a navigation ref with createNavigationContainerRef, you need to use the current property to get the navigation object
    let currentNavigation = navigation
    if (navigation.current) {
      currentNavigation = navigation.current
    }

    let currentRoute = undefined

    // NOTE: This method is not typed correctly but is available and takes care of parsing the router state correctly
    try {
      let isReady = false
      try {
        isReady = (currentNavigation as any).isReady()
      } catch (error) {
        // keep compatibility with older versions of react-navigation
        isReady = true
      }

      if (!isReady) {
        return
      }

      currentRoute = (currentNavigation as any).getCurrentRoute()
    } catch (error) {
      // if this happens, we're not in a navigation context, so we can't track the route
      return
    }

    if (!currentRoute) {
      return
    }

    const { state } = currentRoute
    let { name, params } = currentRoute

    if (state?.routes?.length) {
      const route = state.routes[state.routes.length - 1]
      name = route.name
      params = route.params
    }

    const currentRouteName = options?.routeToName?.(name, params) || name || 'Unknown'

    if (currentRouteName) {
      const properties = options?.routeToProperties?.(currentRouteName, params)
      posthog.screen(currentRouteName, properties)
    }
  }, [navigation, options, posthog])

  // eslint-disable-next-line react-hooks/rules-of-hooks
  useEffect(() => {
    // NOTE: The navigation stacks may not be fully rendered initially. This means the first route can be missed (it doesn't update useNavigationState)
    // If missing we simply wait a tick and call it again.
    if (!routes) {
      setTimeout(trackRoute, 1)
      return
    }
    trackRoute()
  }, [routes, trackRoute])
}

export const useNavigationTracker = OptionalReactNativeNavigation
  ? _useNavigationTracker
  : _useNavigationTrackerDisabled

/*
 * Wix Navigation (react-native-navigation)
 *
 * Wix Navigation uses a very different paradigm for rendering screens, with a more imperative / config driven approach
 * Instead of hooking into the natural React lifecycle, it provides a very different API which we can hook into and use instead.
 */

import { OptionalReactNativeNavigationWix } from '../optional/OptionalReactNativeNavigationWix'
import { PostHog } from '../posthog-rn'
import { PostHogAutocaptureOptions } from '../types'

export const withReactNativeNavigation = (posthog: PostHog, options: PostHogAutocaptureOptions = {}): boolean => {
  if (!OptionalReactNativeNavigationWix) {
    return false
  }

  const Navigation = OptionalReactNativeNavigationWix.Navigation

  // Equivalent of `useNavigationTracker`
  Navigation.events().registerComponentDidAppearListener(({ componentName, passProps }) => {
    if (!(options.captureScreens ?? true)) {
      return
    }

    const currentRouteName =
      options?.navigation?.routeToName?.(componentName, passProps || {}) || componentName || 'Unknown'

    if (currentRouteName) {
      const properties = options?.navigation?.routeToProperties?.(currentRouteName, passProps || {})
      posthog.screen(currentRouteName, properties)
    }
  })

  return true
